# state_inspector.py
import tiktoken
from agent_state import AgentState

DEFAULT_TOKEN_LIMIT = 8192  # adjust for your model

def estimate_tokens(messages: list, model: str = "gpt-4") -> int:
    """Approximate token count using tiktoken (works for any OpenAI-style tokenizer)."""
    try:
        enc = tiktoken.encoding_for_model(model)
    except KeyError:
        enc = tiktoken.get_encoding("cl100k_base")  # Anthropic-compatible approx
    total = 0
    for msg in messages:
        content = msg.get("content", "")
        if isinstance(content, str):
            total += len(enc.encode(content))
        elif isinstance(content, list):
            for block in content:
                if isinstance(block, dict) and block.get("type") == "text":
                    total += len(enc.encode(block["text"]))
                elif hasattr(block, "text"):
                    total += len(enc.encode(block.text))
    return total

def state_summary(state: AgentState, token_limit: int = DEFAULT_TOKEN_LIMIT) -> dict:
    token_count = estimate_tokens(state.messages)
    context_pct = token_count / token_limit * 100

    tool_name_counts: dict[str, int] = {}
    for r in state.tool_results:
        tool_name_counts[r.tool_name] = tool_name_counts.get(r.tool_name, 0) + 1

    return {
        "session_id":       state.session_id,
        "turn_count":       state.turn_count,
        "message_count":    len(state.messages),
        "token_count":      token_count,
        "token_limit":      token_limit,
        "context_pct":      round(context_pct, 1),
        "context_pressure": "HIGH" if context_pct > 80 else "MED" if context_pct > 50 else "OK",
        "tool_calls":       len(state.tool_results),
        "tool_breakdown":   tool_name_counts,
        "errors":           sum(1 for r in state.tool_results if r.error),
        "elapsed_ms":       round(state.elapsed_ms()),
        "plan_progress":    f"{len(state.completed_steps)}/{len(state.plan_steps)}"
                            if state.plan_steps else None,
    }

def print_summary(state: AgentState, token_limit: int = DEFAULT_TOKEN_LIMIT) -> None:
    s = state_summary(state, token_limit)
    bar_width = 30
    filled = int(bar_width * s["context_pct"] / 100)
    bar = "█" * filled + "░" * (bar_width - filled)
    pressure_color = {"HIGH": "\033[91m", "MED": "\033[93m", "OK": "\033[92m"}
    reset = "\033[0m"
    color = pressure_color.get(s["context_pressure"], "")
    print(f"--- State [{s['session_id']}] turn={s['turn_count']} "
          f"elapsed={s['elapsed_ms']}ms ---")
    print(f"  Context: [{bar}] {s['token_count']}/{s['token_limit']} "
          f"({s['context_pct']}%) {color}{s['context_pressure']}{reset}")
    print(f"  Messages: {s['message_count']}  Tool calls: {s['tool_calls']} "
          f"errors: {s['errors']}")
    print(f"  Tools: {s['tool_breakdown']}")
    if s["plan_progress"]:
        print(f"  Plan: {s['plan_progress']} steps done")

from state_inspector import estimate_tokens
from agent_state import AgentState

def diff_states(before: AgentState, after: AgentState) -> dict:
    new_messages = after.messages[len(before.messages):]
    new_tools = after.tool_results[len(before.tool_results):]
    token_before = estimate_tokens(before.messages)
    token_after = estimate_tokens(after.messages)

    return {
        "new_message_count": len(new_messages),
        "new_messages": [
            {
                "role": m["role"],
                "preview": str(m["content"])[:120],
            }
            for m in new_messages
        ],
        "new_tool_calls": [
            {"name": r.tool_name, "latency_ms": round(r.latency_ms),
             "error": r.error}
            for r in new_tools
        ],
        "token_delta": token_after - token_before,
        "turn_delta": after.turn_count - before.turn_count,
    }

def print_diff(before: AgentState, after: AgentState, step: int) -> None:
    d = diff_states(before, after)
    print(f"\n=== Step {step} diff ===")
    print(f"  Tokens: +{d['token_delta']} | Turns: +{d['turn_delta']}")
    for msg in d["new_messages"]:
        print(f"  [{msg['role']}] {msg['preview']}")
    for tool in d["new_tool_calls"]:
        status = f"ERROR: {tool['error']}" if tool["error"] else f"{tool['latency_ms']}ms"
        print(f"  tool:{tool['name']} → {status}")

def inspect_messages(messages: list) -> None:
    """Print a compact view of the messages array."""
    print(f"\nMessages ({len(messages)} total):")
    for i, msg in enumerate(messages):
        role = msg["role"]
        content = msg["content"]

        if isinstance(content, str):
            preview = content[:80].replace("\n", " ")
            print(f"  [{i}] {role}: {preview}")
        elif isinstance(content, list):
            for block in content:
                btype = block.get("type") if isinstance(block, dict) else getattr(block, "type", "?")
                if btype == "text":
                    text = (block.get("text") or block.text)[:80]
                    print(f"  [{i}] {role} text: {text}")
                elif btype == "tool_use":
                    name = block.get("name") or block.name
                    print(f"  [{i}] {role} tool_use: {name}({block.get('input') or block.input})")
                elif btype == "tool_result":
                    tid = block.get("tool_use_id") or block.tool_use_id
                    result_preview = str(block.get("content") or block.content)[:60]
                    print(f"  [{i}] {role} tool_result[{tid[:8]}]: {result_preview}")
        else:
            print(f"  [{i}] {role}: <unknown content type {type(content).__name__}>")

# Usage: after any agent step
# inspect_messages(state.messages)

# Find repeated tool queries — a sign of a loop
def find_repeated_queries(messages: list) -> list[str]:
    queries = []
    for msg in messages:
        content = msg.get("content", [])
        if not isinstance(content, list):
            continue
        for block in content:
            b = block if isinstance(block, dict) else block.__dict__
            if b.get("type") == "tool_use" and b.get("name") == "web_search":
                queries.append(b.get("input", {}).get("query", ""))
    seen, dupes = set(), []
    for q in queries:
        if q in seen:
            dupes.append(q)
        seen.add(q)
    return dupes
